#include "biblia.h"

void Biblia::Carregar2Tessalonicenses(Biblia* b) {
    b->dados[TESSALONICENSES2].nome = wxT("2 Tessalonicenses");

    b->dados[TESSALONICENSES2].capitulos[1].versos[1] = wxT("Paulo, Silvano e Timóteo à igreja dos tessalonicenses, em Deus nosso Pai e no Senhor Jesus Cristo:");
    b->dados[TESSALONICENSES2].capitulos[1].versos[2] = wxT("Graças a vós, e paz da parte de Deus Pai e do Senhor Jesus Cristo.");
    b->dados[TESSALONICENSES2].capitulos[1].versos[3] = wxT("Sempre devemos, irmãos, dar graças a Deus por vós, como é justo, porque a vossa fé cresce muitíssimo e o amor de cada um de vós transborda de uns para com os outros.");
    b->dados[TESSALONICENSES2].capitulos[1].versos[4] = wxT("De maneira que nós mesmos nos gloriamos de vós nas igrejas de Deus por causa da vossa constância e fé em todas as perseguições e aflições que suportais;");
    b->dados[TESSALONICENSES2].capitulos[1].versos[5] = wxT("o que é prova clara do justo juízo de Deus, para que sejais havidos por dignos do reino de Deus, pelo qual também padeceis;");
    b->dados[TESSALONICENSES2].capitulos[1].versos[6] = wxT("se de fato é justo diante de Deus que ele dê em paga tribulação aos que vos atribulam,");
    b->dados[TESSALONICENSES2].capitulos[1].versos[7] = wxT("e a vós, que sois atribulados, alívio juntamente conosco, quando do céu se manifestar o Senhor Jesus com os anjos do seu poder em chama de fogo,");
    b->dados[TESSALONICENSES2].capitulos[1].versos[8] = wxT("e tomar vingança dos que não conhecem a Deus e dos que não conhecem a Deus e dos que não obedecem ao evangelho de nosso Senhor Jesus;");
    b->dados[TESSALONICENSES2].capitulos[1].versos[9] = wxT("os quais sofrerão, como castigo, a perdição eterna, banidos da face do senhor e da glória do seu poder,");
    b->dados[TESSALONICENSES2].capitulos[1].versos[10] = wxT("quando naquele dia ele vier para ser glorificado nos seus santos e para ser admirado em todos os que tiverem crido {porquanto o nosso testemunho foi crido entre vós}.");
    b->dados[TESSALONICENSES2].capitulos[1].versos[11] = wxT("Pelo que também rogamos sempre por vós, para que o nosso Deus vos faça dignos da sua vocação, e cumpra com poder todo desejo de bondade e toda obra de fé.");
    b->dados[TESSALONICENSES2].capitulos[1].versos[12] = wxT("para que o nome de nosso Senhor Jesus seja glorificado em vós, e vós nele, segundo a graça de nosso Deus e do Senhor Jesus Cristo.");

    b->dados[TESSALONICENSES2].capitulos[2].versos[1] = wxT("Ora, quanto à vinda de nosso Senhor Jesus Cristo e à nossa reunião com ele, rogamos-vos, irmãos,");
    b->dados[TESSALONICENSES2].capitulos[2].versos[2] = wxT("que não vos movais facilmente do vosso modo de pensar, nem vos perturbeis, quer por espírito, quer por palavra, quer por epístola como enviada de nós, como se o dia do Senhor estivesse já perto.");
    b->dados[TESSALONICENSES2].capitulos[2].versos[3] = wxT("Ninguém de modo algum vos engane; porque isto não sucederá sem que venha primeiro a apostasia e seja revelado o homem do pecado, o filho da perdição,");
    b->dados[TESSALONICENSES2].capitulos[2].versos[4] = wxT("aquele que se opõe e se levanta contra tudo o que se chama Deus ou é objeto de adoração, de sorte que se assenta no santuário de Deus, apresentando-se como Deus.");
    b->dados[TESSALONICENSES2].capitulos[2].versos[5] = wxT("Não vos lembrais de que eu vos dizia estas coisas quando ainda estava convosco?");
    b->dados[TESSALONICENSES2].capitulos[2].versos[6] = wxT("E agora vós sabeis o que o detém para que a seu próprio tempo seja revelado.");
    b->dados[TESSALONICENSES2].capitulos[2].versos[7] = wxT("Pois o mistério da iniqüidade já opera; somente há um que agora o detém até que seja posto fora;");
    b->dados[TESSALONICENSES2].capitulos[2].versos[8] = wxT("e então será revelado esse iníquo, a quem o Senhor Jesus matará como o sopro de sua boca e destruirá com a manifestação da sua vinda;");
    b->dados[TESSALONICENSES2].capitulos[2].versos[9] = wxT("a esse iníquo cuja vinda é segundo a eficácia de Satanás com todo o poder e sinais e prodígios de mentira,");
    b->dados[TESSALONICENSES2].capitulos[2].versos[10] = wxT("e com todo o engano da injustiça para os que perecem, porque não receberam o amor da verdade para serem salvos.");
    b->dados[TESSALONICENSES2].capitulos[2].versos[11] = wxT("E por isso Deus lhes envia a operação do erro, para que creiam na mentira;");
    b->dados[TESSALONICENSES2].capitulos[2].versos[12] = wxT("para que sejam julgados todos os que não creram na verdade, antes tiveram prazer na injustiça.");
    b->dados[TESSALONICENSES2].capitulos[2].versos[13] = wxT("Mas nós devemos sempre dar graças a Deus por vós, irmãos, amados do Senhor, porque Deus vos escolheu desde o princípio para a santificação do espírito e a fé na verdade,");
    b->dados[TESSALONICENSES2].capitulos[2].versos[14] = wxT("e para isso vos chamou pelo nosso evangelho, para alcançardes a glória de nosso Senhor Jesus Cristo.");
    b->dados[TESSALONICENSES2].capitulos[2].versos[15] = wxT("Assim, pois, irmãos, estai firmes e conservai as tradições que vos foram ensinadas, seja por palavra, seja por epístola nossa.");
    b->dados[TESSALONICENSES2].capitulos[2].versos[16] = wxT("E o próprio Senhor nosso, Jesus Cristo, e Deus nosso Pai que nos amou e pela graça nos deu uma eterna consolação e boa esperança,");
    b->dados[TESSALONICENSES2].capitulos[2].versos[17] = wxT("console os vossos corações e os confirme em toda boa obra e palavra.");

    b->dados[TESSALONICENSES2].capitulos[3].versos[1] = wxT("Finalmente, irmãos, orai por nós, para que a palavra do Senhor se propague e seja glorificada. como também o é entre vós,");
    b->dados[TESSALONICENSES2].capitulos[3].versos[2] = wxT("e para que sejamos livres de homens perversos e maus; porque a fé não é de todos.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[3] = wxT("Mas fiel é o Senhor, o qual vos confirmará e guardará do maligno.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[4] = wxT("E, quanto a vós, confiamos no Senhor que não só fazeis, mas fareis o que vos mandamos.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[5] = wxT("Ora, o Senhor encaminhe os vossos corações no amor de Deus e na constância de Cristo.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[6] = wxT("mandamo-vos, irmãos, em nome do Senhor Jesus Cristo, que vos aparteis de todo irmão que anda desordenadamente, e não segundo a tradição que de nós recebestes.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[7] = wxT("Porque vós mesmos sabeis como deveis imitar-nos, pois que não nos portamos desordenadamente entre vós,");
    b->dados[TESSALONICENSES2].capitulos[3].versos[8] = wxT("nem comemos de graça o pão de ninguém, antes com labor e fadiga trabalhávamos noite e dia para não sermos pesados a nenhum de vós.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[9] = wxT("Não porque não tivéssemos direito, mas para vos dar nós mesmos exemplo, para nos imitardes.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[10] = wxT("Porque, quando ainda estávamos convosco, isto vos mandamos: se alguém não quer trabalhar, também não coma.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[11] = wxT("Porquanto ouvimos que alguns entre vós andam desordenadamente, não trabalhando, antes intrometendo-se na vida alheia;");
    b->dados[TESSALONICENSES2].capitulos[3].versos[12] = wxT("a esses tais, porém, ordenamos e exortamos por nosso Senhor Jesus Cristo que, trabalhando sossegadamente, comam o seu próprio pão.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[13] = wxT("Vós, porém, irmãos, não vos canseis de fazer o bem.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[14] = wxT("Mas, se alguém não obedecer à nossa palavra por esta carta, notai-o e não tenhais relações com ele, para que se envergonhe;");
    b->dados[TESSALONICENSES2].capitulos[3].versos[15] = wxT("todavia não o considereis como inimigo, mas admoestai-o como irmão.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[16] = wxT("Ora, o próprio Senhor da paz vos dê paz sempre e de toda maneira. O Senhor seja com todos vós.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[17] = wxT("Esta saudação é de próprio punho, de Paulo, o que é o sinal em cada epístola; assim escrevo.");
    b->dados[TESSALONICENSES2].capitulos[3].versos[18] = wxT("A graça de nosso Senhor Jesus Cristo seja com todos vós.");

}
